// ─── Status Color Mapping ──────────────────────────────────
Color statusColor(String status) => switch (status) {
  'ORDER_PLACED' => AppColors.statusOrderPlaced,
  'OFFICE_STOCK' => AppColors.statusOfficeStock,
  'LISTED' => AppColors.statusListed,
  'POIZON_STORAGE' => AppColors.statusPoizonStorage,
  'SOLD' => AppColors.statusSold,
  'OUTGOING' => AppColors.statusOutgoing,
  'IN_INSPECTION' => AppColors.statusInspection,
  'SETTLED' || 'DEFECT_SETTLED' => AppColors.statusSettled,
  'DEFECT_FOR_SALE' || 'DEFECT_SOLD' => AppColors.statusDefectSale,
  'DEFECT_HELD' => AppColors.statusDefectHeld,
  'RETURNING' => AppColors.statusReturning,
  'CANCEL_RETURNING' => AppColors.statusCancelReturning,
  'REPAIRING' => AppColors.statusRepairing,
  _ => AppColors.statusEtc,
};

